@dataclass
class CountDownState:
    counter: int

@dataclass
class CountDown(BaseNode[CountDownState, None, int]):
    async def run(
        self, ctx: GraphRunContext[CountDownState]
    ) -> CountDown | End[int]:
        if ctx.state.counter <= 0:
            return End(ctx.state.counter)
        ctx.state.counter -= 1
        return CountDown()

